namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and communication." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and human civilization." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor", Bio = "Dr. Chen specializes in algorithms and machine learning. She has published over 50 papers in top-tier conferences and holds a Ph.D. from MIT.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Miller", Title = "Associate Professor", Bio = "Dr. Miller's research focuses on abstract algebra and number theory. He received the University Teaching Excellence Award in 2023.", Email = "j.miller@university.edu" },
            new() { Id = 3, Name = "Dr. Emily Rodriguez", Title = "Professor", Bio = "Dr. Rodriguez is a leading researcher in quantum mechanics with 20 years of teaching experience.", Email = "e.rodriguez@university.edu" },
            new() { Id = 4, Name = "Dr. Michael Thompson", Title = "Associate Professor", Bio = "Dr. Thompson is an award-winning author and literary critic specializing in modern American literature.", Email = "m.thompson@university.edu" },
            new() { Id = 5, Name = "Dr. Lisa Park", Title = "Professor", Bio = "Dr. Park is a historian of East Asian studies with expertise in cultural exchange during the Silk Road era.", Email = "l.park@university.edu" },
            new() { Id = 6, Name = "Dr. David Walsh", Title = "Lecturer", Bio = "Dr. Walsh brings industry experience in software engineering and focuses on practical programming skills.", Email = "d.walsh@university.edu" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "An introductory course covering fundamental programming concepts using Python. Topics include variables, control structures, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[5], IsFeatured = true },
            new() { Id = 2, Code = "CS 301", Title = "Algorithms and Data Structures", Description = "Advanced study of algorithm design and analysis. Covers sorting, graph algorithms, dynamic programming, and computational complexity.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 3, Code = "CS 450", Title = "Machine Learning", Description = "Introduction to machine learning algorithms including supervised and unsupervised learning, neural networks, and model evaluation.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = false },
            new() { Id = 4, Code = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, determinants, and eigenvalues with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 5, Code = "MATH 301", Title = "Abstract Algebra", Description = "Introduction to algebraic structures including groups, rings, and fields.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, Department = _departments[1], Instructor = _instructors[1], IsFeatured = false },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM + Fri Lab", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2], IsFeatured = true },
            new() { Id = 7, Code = "PHYS 302", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, quantum states, and measurement.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 3, Department = _departments[2], Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 8, Code = "ENG 101", Title = "Composition and Rhetoric", Description = "Development of academic writing skills with emphasis on argumentation, research, and clear communication.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = false },
            new() { Id = 9, Code = "ENG 250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", DepartmentId = 4, Department = _departments[3], Instructor = _instructors[3], IsFeatured = true },
            new() { Id = 10, Code = "HIST 101", Title = "World Civilizations", Description = "Survey of major world civilizations from ancient times to the modern era.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[4], IsFeatured = false },
            new() { Id = 11, Code = "HIST 340", Title = "The Silk Road", Description = "Exploration of cultural, economic, and technological exchange along the ancient Silk Road trade routes.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", DepartmentId = 5, Department = _departments[4], Instructor = _instructors[4], IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

