        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in CatalogService.GetDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@{
    var courses = CatalogService.GetCourses(Search, DepartmentId);
}

@if (courses.Count == 0)
{
    <p class="text-muted">No courses found matching your criteria.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.Department.Name</td>
                    <td>@course.Credits</td>
                    <td><a href="/courses/@course.Id">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="/courses">Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code &mdash; @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@course.Description</p>

            <h3>Schedule</h3>
            <p>@course.Schedule</p>

            <h3>Credits</h3>
            <p>@course.Credits</p>

            <a href="/enroll?courseId=@course.Id" class="btn btn-primary mt-3">Request Enrollment</a>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Instructor.Name</h6>
                    <p class="card-text"><em>@course.Instructor.Title</em></p>
                    <p class="card-text">@course.Instructor.Bio</p>
                    <p class="card-text"><small class="text-muted">@course.Instructor.Email</small></p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private UniversityCourseCatalog.Models.Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <strong>Request submitted successfully!</strong> Your enrollment request has been received and will be processed.
    </div>
    <a href="/courses">Browse more courses</a>
}
else
{
    if (Error)
    {
        <div class="alert alert-danger">
            Please fill in all required fields and select a valid course.
        </div>
    }

    <form method="post" class="col-md-6">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in CatalogService.GetCourses())
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.Code - @course.Title</option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm]
    public UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool Submitted { get; set; }
    private bool Error { get; set; }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? "GET"))
        {
            var success = CatalogService.SubmitEnrollmentRequest(Model);
            if (success)
                Submitted = true;
            else
                Error = true;
        }
    }

    [CascadingParameter]
    public HttpContext? HttpContextAccessor { get; set; }
}

