    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool Submitted { get; set; }
    private bool Error { get; set; }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? "GET"))
        {
            var success = CatalogService.SubmitEnrollmentRequest(Model);
            if (success)
                Submitted = true;
            else
                Error = true;
        }
    }

    [CascadingParameter]
    public HttpContext? HttpContextAccessor { get; set; }
}

